import sys

bridge = """<script id="sl-bridge">(function(){if(window.self===window.top)return;var P=window.parent,O="*",mode="off",highlights=[],focusId=null,styleEl=null;var SEL="h1,h2,h3,h4,h5,h6,p,span,a,button,li,img,figure,[data-sl-id]";function getType(el){var t=el.tagName.toLowerCase();if(t==="img")return"image";if(el.querySelector("img"))return"image";return"text";}function getVal(el){var t=el.tagName.toLowerCase();if(t==="img")return el.src||"";var i=el.querySelector("img");if(i)return i.src||"";return(el.textContent||"").trim().slice(0,200);}function getPage(){return window.location.pathname.replace(/^\//,"")||"home";}function detectRoutes(){var r=new Set(["home"]);document.querySelectorAll("a[href]").forEach(function(a){var h=a.getAttribute("href");if(h&&h.startsWith("/")&&h.length>1){var s=h.replace(/^\//,"").split("/")[0].split("?")[0];if(s)r.add(s);}});return Array.from(r);}function assignIds(){var p=getPage(),c={};document.querySelectorAll(SEL).forEach(function(el){if(el.getAttribute("data-sl-id"))return;var t=el.tagName.toLowerCase(),ty=getType(el),k=p+"-"+ty+"-"+t;c[k]=(c[k]||0)+1;el.setAttribute("data-sl-id","sl-"+p+"-"+ty+"-"+t+"-"+c[k]);el.setAttribute("data-sl-type",ty);});}function applyLocks(){document.querySelectorAll("[data-sl-locked]").forEach(function(el){el.removeAttribute("data-sl-locked");});highlights.forEach(function(item){var el=document.querySelector('[data-sl-id="'+item.slId+'"]');if(el)el.setAttribute("data-sl-locked","true");});}function injectCSS(){if(styleEl)styleEl.remove();styleEl=document.createElement("style");var css="";if(mode==="select"){css+="[data-sl-id]{cursor:crosshair!important;transition:outline .1s,background .1s;}[data-sl-id]:hover{outline:2px solid #22c55e!important;background:rgba(34,197,94,.08)!important;}[data-sl-id][data-sl-locked]{cursor:not-allowed!important;}[data-sl-id][data-sl-locked]:hover{outline:none!important;background:transparent!important;}";}if(mode==="select"||mode==="highlight"){highlights.forEach(function(item){var c=item.action==="DELETE"?"#ef4444":"#3b82f6",bg=item.action==="DELETE"?"rgba(239,68,68,.08)":"rgba(59,130,246,.08)";css+='[data-sl-id="'+item.slId+'"]{outline:2px solid '+c+'!important;background:'+bg+'!important;cursor:not-allowed!important;}';});}if(mode==="readonly"&&focusId){css+="*{pointer-events:none!important;cursor:default!important;}"+'[data-sl-id="'+focusId+'"]{outline:3px solid #3b82f6!important;background:rgba(59,130,246,.12)!important;pointer-events:none!important;}';}styleEl.textContent=css;document.head.appendChild(styleEl);}window.addEventListener("message",function(e){var m=e.data;if(!m||!m.type)return;if(m.type==="SL_SET_MODE"){mode=m.mode||"off";assignIds();injectCSS();}else if(m.type==="SL_SET_HIGHLIGHTS"){highlights=m.items||[];applyLocks();injectCSS();}else if(m.type==="SL_FOCUS_ELEMENT"){mode="readonly";focusId=m.slId;injectCSS();var t=document.querySelector('[data-sl-id="'+m.slId+'"]');if(t)t.scrollIntoView({behavior:"smooth",block:"center"});}else if(m.type==="SL_RESET"){mode="off";highlights=[];focusId=null;if(styleEl)styleEl.remove();document.querySelectorAll("[data-sl-locked]").forEach(function(el){el.removeAttribute("data-sl-locked");});}});document.addEventListener("click",function(e){if(mode!=="select")return;var el=e.target.closest("[data-sl-id]");if(!el||el.getAttribute("data-sl-locked"))return;e.preventDefault();e.stopPropagation();P.postMessage({type:"SL_ELEMENT_SELECTED",slId:el.getAttribute("data-sl-id"),elementType:el.getAttribute("data-sl-type")||getType(el),currentValue:getVal(el),page:getPage()},O);},true);function init(){assignIds();var attempts=0;var retry=setInterval(function(){assignIds();attempts++;if(attempts>=20)clearInterval(retry);},500);var routes=detectRoutes();P.postMessage({type:"SL_READY",routes:routes,currentPage:getPage()},O);var op=history.pushState.bind(history),or=history.replaceState.bind(history);history.pushState=function(){op.apply(history,arguments);setTimeout(function(){assignIds();applyLocks();injectCSS();P.postMessage({type:"SL_ROUTE_CHANGED",route:getPage()},O);},300);};history.replaceState=function(){or.apply(history,arguments);setTimeout(function(){assignIds();P.postMessage({type:"SL_ROUTE_CHANGED",route:getPage()},O);},300);};window.addEventListener("popstate",function(){setTimeout(function(){assignIds();P.postMessage({type:"SL_ROUTE_CHANGED",route:getPage()},O);},300);});}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init);}else{init();}})();</script>"""

content = open(sys.argv[1]).read()

# Supprimer tout script sl-bridge existant pour eviter les doublons
import re
content = re.sub(r'<script[^>]*id=["\']sl-bridge["\'][^>]*>.*?</script>', '', content, flags=re.DOTALL)

# Supprimer le script bridge.siteland.co si present
content = re.sub(r'<script[^>]*>[\s\S]*?bridge\.siteland\.co[\s\S]*?</script>', '', content)

# Injecter le bridge avant </head>
content = content.replace("</head>", bridge + "\n</head>", 1)

open(sys.argv[1], "w").write(content)
print("Bridge injected successfully into", sys.argv[1])
